			"type": "number",
			"suggestedvalues": [
				"1",
				"25",
				"100"
			]
		},
		"2": {
			"label": "Displayed backlog threshold ",
			"description": "The number displayed as the backlog threshold. Useful if a backlog category has members that should not be counted towards the backlog (e.g. subcategories or example pages). See documentation for more information.",
			"type": "number",
			"suggestedvalues": [
				"1",
				"10"
			]
		},
		"disabled": {
			"description": "If true, disables the template. This is functionally equivalent to removing the template.",
			"example": "yes",
			"type": "boolean",
			"default": "no"
		},
		"silent": {
			"description": "If true, hides the template entirely when there is no backlog. This parameter is ignored if not used on a category page",
			"example": "yes",
			"type": "boolean",
			"default": "no"
		},
		"admin": {
			"label": "Administrative backlog?",
			"description": "If true, signifies that clearing the backlog requires the use of administrators' tools.",
			"example": "yes",
			"type": "boolean",
			"default": "no"
		},
		"backloglink": {
			"description": "The destination of the backlog wikilink. Defaults to \":Category:Administrative backlog\" if |admin=yes",
			"type": "string",
			"default": ":Category:Wikipedia backlog",
			"label": "Backlog link"
		},
		"demospace": {
			"description": "For use in testing. Makes the template function as if it were placed in the given namespace.",
			"type": "string",
			"suggestedvalues": [
				"Category",
				"Wikipedia"
			]
		},
		"page": {
			"description": "The type of location of the backlog. Defaults to \"This category\" if used in that namespace. Otherwise, defaults to \"This page\".",
			"type": "string",
			"default": "This page"
		},
		"bot": {
			"description": "The name of the bot which updates this notice, without the User: prefix.",
			"example": "RMCD bot",
			"type": "wiki-user-name"
		},
		"auto": {
			"label": "Automatically updated?",
			"description": "If true, says that the notice will automatically hide itself. Note: this only affects the message on the template; it does NOT facilitate automatically removing the notice.",
			"example": "yes",
			"type": "boolean",
			"default": "no"
		},
		"remove": {
			"description": "If true, asks editors to remove the message entirely when the backlog is cleared. Otherwise, the template will ask editors to change the template to {{no backlog}}.",
			"example": "no",
			"type": "boolean",
			"default": "yes"
		}
	},
	"description": "A banner to keep track of backlogs"
}
